// 2.8.0 - 2022-07-09 - raj -  STRY0119137 - Stretch- Template UI Clean Up- Delete Top Template Task Confirmation Modal (make sure the client always has the template task number and template task name)
// 2.8.0 - 2022-08-23 - raj -  DFCT0011200 - "Task Order" form field does Not display on Template Subtask modal when creating 2nd subtask
// 2.8.x | 2023-04-30 | raj  | STRY0138448 - Apply ACL to New Template/Template Subtask Form for Offices and Members in Private Structure
// 
// Script Continued Below
(function executeRule(current, previous /*null when async*/) {
	// DFCT0011200
	if(current.parent){
		g_scratchpad.numberOfParentChildren = current.parent.calchaschildren;	
	} else {
		g_scratchpad.numberOfParentChildren = 0;
	}
	// STRY0119137 - make sure the client always has the template number and template name
	g_scratchpad.templateTaskNumber = current.number;
	g_scratchpad.templateTaskName = current.short_description;
	g_scratchpad.templateId = current.getValue("tasker_process_definition");
	g_scratchpad.topTemplateTaskId = current.tasker_process_definition.parent_task_def;


	// STRY0113084 
	g_scratchpad.suspense_date_label = current.u_suspense_date.getLabel();
	g_scratchpad.u_warning_projected_due_date_before_child	 = current.u_warning_projected_due_date_before_child;
	g_scratchpad.u_warning_projected_due_date_after_parent	 = current.u_warning_projected_due_date_after_parent;


	// STRY0091294
	g_scratchpad.isSuspenseDateRequired = gs.getProperty('x_153465_discovert.isSuspenseDateRequired');

	//FOR ALL RECORDS WE ARE SETTING THE SHARED DOCS FLAGS
	// RJ - STRY0063760 - use the new function to get the switches consistently.
	var tDS = new taskerDocumentScripts();
	var currentAttachDocSettings = tDS.getAttachmentAndDocumentSettings(current);

	//2.5.13 | ATTACH | KT: STRY0072011
	g_scratchpad.SNAttachmentsON = currentAttachDocSettings.sNOWAttachmentsOn;

	// RAJ 2020.03.18  STRY0063747 - this passes the value of the Shared Documents setting to the form.
	// the form will check this value to determine if the Related List for "Shared Attachments" should be displayed or hidden in the associated
	// "onLoad script"
	g_scratchpad.sharedAttachmentsFolder = currentAttachDocSettings.sharingAttachments && currentAttachDocSettings.sNOWAttachmentsOn;

	// RAJ 2020.03.18  STRY0063747 - this passes the value of the Shared Documents setting to the form.
	// the form will check this value to determine if the Widget for "Shared Documents" should be displayed or hidden in the associated
	// "onLoad script"
	g_scratchpad.sharedDocumentsFolder = currentAttachDocSettings.sharingDocuments && currentAttachDocSettings.docIntDocumentsOn;
	// STRY0080195 
	g_scratchpad.docIntDocumentsOn = currentAttachDocSettings.docIntDocumentsOn;

	// RAJ - STRY 0011909 - modify process template
	// moved from process definition here when implementing Top Tasker Definition
	if (current.isNewRecord() && current.parent.nil()) {

		// STRY0065506 - added  fields added to the Template for parity
		// if new, copy any defaults set on the Template form into the Top Task
		if(!current.tasker_process_definition.nil()){

			// STRY0065506 - added  fields added to the Template for parity
			current.assigned_to_individual = current.tasker_process_definition.u_assigned_member;
			current.classification = current.tasker_process_definition.classification;
			current.instructions = current.tasker_process_definition.description;
			current.u_objective = current.tasker_process_definition.u_objective;
			current.primary_assignee = current.tasker_process_definition.u_primary_assignee;
			current.primary_office = current.tasker_process_definition.u_primary_office;
			current.assigned_to_group = current.tasker_process_definition.u_restricted_group;
			current.short_description = current.tasker_process_definition.short_description;
			current.tasking_authority = current.tasker_process_definition.u_tasking_authority;
			// STRY0138448
			current.u_privacy = current.tasker_process_definition.u_privacy;
			// STRY0076904
			current.u_wait_for_subtasks_to_finish = current.tasker_process_definition.u_wait_for_subtasks_to_finish;

		}

		// STRY0065506 -if any of the defaults were not set on the template, then load them

		// Default the Process Definition Fields on creation here
		// Lookup the default ou for this user and set the Primary OU
		var OrgScripts = new OrganizationalScripts();
		var defaultOU = OrgScripts.GetUserDefaultOU(gs.getUserID());
		if(defaultOU.toString() != ''){
			// STRY0065506 -if any of the defaults were not set on the template, then load them
			if(current.primary_office.nil())
				current.primary_office = defaultOU;
			// STRY0065506 -if any of the defaults were not set on the template, then load them
			if(current.primary_assignee.nil())
				current.primary_assignee = defaultOU;

			// STRY0065506 -if any of the defaults were not set on the template, then load them
			if(current.tasking_authority.nil()){
				// RAJ 2018-02-20 - STRY0010804 - default Tasking Authority to the current user's OU
				var defaultTA;
				defaultTA = OrgScripts.GetUserDefaultTaskingAuthority(defaultOU);
				if(defaultTA.toString() != ''){
					current.tasking_authority = defaultTA;
				// else added to address error in the load code
				} else {
					current.tasking_authority = defaultOU;
				}
			}
		}
	}

})(current, previous);
